def seed_shared_icons():
    """Insert base SVG icons into shared_assets DB.

    Idempotent: skips icons that already exist by name.
    No Cloudinary upload needed — SVG content is stored in metadata_json
    and rasterized at render time by cairosvg.
    """
    seeded = 0
    skipped = 0

    for name, tags, svg_content in _SEED_ICONS:
        existing = get_asset_by_name(name, category="icon")
        if existing:
            skipped += 1
            continue

        create_asset(
            name=name,
            url="",  # no CDN needed; svg_content is used directly
            tags=tags,
            category="icon",
            asset_type="svg",
            source="seed",
            metadata={"svg_content": svg_content},
        )
        seeded += 1

    if seeded:
        logger.info("[seed_icons] Seeded %d icons, skipped %d (already exist).", seeded, skipped)
